#include <bits/stdc++.h>using namespace std;#define ll long long #define FIO ios::sync_with_stdio(false), cin.tie(nullptr)  void solve() {    ll n ,c ;    cin >> n >> c ;    vector<ll> a(n) ;    for(ll i=0 ; i<n ;i++) cin >>a[i] ;        ll l = 0 , r = 1e9+1 ;    while(l <= r) {        ll mid = l +(r-l)/2 ;                ll sum = 0 ;        for(ll i=0 ; i<n ;i++) {            sum += (a[i]+2*mid) * (a[i]+2*mid) ;            if(sum > c) break;        }        if(sum == c) {            cout << mid << endl ;            return ;        }         if(sum > c) {            r = mid - 1;        } else {            l = mid + 1;        }            }  } int main() {    FIO;    int t;    cin >> t;    while (t--) {        solve();    }    return 0;}